package pl.msurvival.market;
import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.configuration.ConfigurationSection;import org.bukkit.configuration.file.YamlConfiguration;import org.bukkit.entity.Player;import org.bukkit.event.*;import org.bukkit.event.inventory.*;import org.bukkit.inventory.*;import org.bukkit.inventory.meta.ItemMeta;import org.bukkit.persistence.PersistentDataType;import org.bukkit.plugin.java.JavaPlugin;import java.io.File;import java.util.*;
public final class MSurvivalMarket extends JavaPlugin implements Listener{File f;YamlConfiguration data;NamespacedKey action;public void onEnable(){saveDefaultConfig();action=new NamespacedKey(this,"a");f=new File(getDataFolder(),"balances.yml");if(!f.exists())try{getDataFolder().mkdirs();f.createNewFile();}catch(Exception e){e.printStackTrace();}data=YamlConfiguration.loadConfiguration(f);Bukkit.getPluginManager().registerEvents(this,this);}public void onDisable(){save();}
public boolean onCommand(CommandSender s,Command c,String l,String[] a){String cmd=c.getName().toLowerCase();if((cmd.equals("rynek")||cmd.equals("sklep"))&&s instanceof Player p){open(p);return true;}if(cmd.equals("kosz")&&s instanceof Player p){p.openInventory(Bukkit.createInventory(null,54,col("&c&lKOSZ")));return true;}if(cmd.equals("kasa")&&s instanceof Player p){p.sendMessage(msg("balance").replace("%money%",money(bal(p.getName()))));return true;}if((cmd.equals("sell")||cmd.equals("sellall"))&&s instanceof Player p){double e=sellAll(p);p.sendMessage(pref()+col("&aSprzedano za &e"+money(e)+"$"));return true;}if(cmd.equals("pay")&&s instanceof Player p&&a.length>1){double am=parse(a[1]);if(am<=0||bal(p.getName())<am){p.sendMessage(msg("no-money"));return true;}add(p.getName(),-am);add(a[0],am);p.sendMessage(pref()+col("&aWysłano."));return true;}if(cmd.equals("rynekadmin")&&s.hasPermission("msurvival.market.admin")&&a.length>2){add(a[1],parse(a[2]));s.sendMessage("ok");return true;}return true;}
void open(Player p){Inventory inv=Bukkit.createInventory(null,45,col("&6&lRYNEK MSURVIVAL"));fill(inv);inv.setItem(10,btn(Material.BAMBOO,"&a&lSkup farm","sell",List.of("&7Bambus i trzcina są bardzo wartościowe","&eKliknij: sprzedaj wszystko")));inv.setItem(12,btn(Material.DIAMOND,"&b&lSkup surowców","sell",List.of("&7Sprzedaje wszystkie itemy z configu")));inv.setItem(14,btn(Material.TRIPWIRE_HOOK,"&6&lKlucze za dolary","keys",List.of("&7Wszystkie klucze są dostępne","&7Ceny są wysokie")));inv.setItem(16,btn(Material.NETHER_STAR,"&e&lSklep specjalny","items",List.of("&7Elytry, totemy, jabłka")));inv.setItem(31,btn(Material.GOLD_INGOT,"&a&lKasa: &e"+money(bal(p.getName()))+"$","none",List.of("&7Twoje dolary")));p.openInventory(inv);} 
void keys(Player p){Inventory inv=Bukkit.createInventory(null,27,col("&6&lRYNEK &8» &eKLUCZE"));fill(inv);String[] ks={"klasyczny","zelazny","diamentowy","epic","legendarny","mityczny","boski"};int[] sl={10,11,12,13,14,15,16};for(int i=0;i<ks.length;i++){double pr=getConfig().getDouble("server-shop.keys."+ks[i]);inv.setItem(sl[i],btn(Material.TRIPWIRE_HOOK,"&e&l"+ks[i].toUpperCase(),"key:"+ks[i],List.of("&7Cena: &e"+money(pr)+"$","&aKliknij aby kupić")));}p.openInventory(inv);} 
void items(Player p){Inventory inv=Bukkit.createInventory(null,27,col("&6&lRYNEK &8» &eITEMY"));fill(inv);int slot=10;ConfigurationSection s=getConfig().getConfigurationSection("server-shop.items");if(s!=null)for(String k:s.getKeys(false)){try{Material m=Material.valueOf(k);inv.setItem(slot++,btn(m,"&e&l"+k,"item:"+k,List.of("&7Cena: &e"+money(s.getDouble(k))+"$")));if(slot>16)break;}catch(Exception ignored){}}p.openInventory(inv);} 
@EventHandler public void click(InventoryClickEvent e){if(!(e.getWhoClicked() instanceof Player p))return;String t=e.getView().getTitle();if(t.equals(col("&6&lRYNEK MSURVIVAL"))||t.equals(col("&6&lRYNEK &8» &eKLUCZE"))||t.equals(col("&6&lRYNEK &8» &eITEMY"))){e.setCancelled(true);String a=act(e.getCurrentItem());if(a==null)return;if(a.equals("sell")){double er=sellAll(p);p.sendMessage(pref()+col("&aSprzedano za &e"+money(er)+"$"));p.closeInventory();}else if(a.equals("keys"))keys(p);else if(a.equals("items"))items(p);else if(a.startsWith("key:")){String k=a.substring(4);buy(p,getConfig().getDouble("server-shop.keys."+k),()->Bukkit.dispatchCommand(Bukkit.getConsoleSender(),"keyadmin give "+p.getName()+" "+k+" 1"));}else if(a.startsWith("item:")){String m=a.substring(5);buy(p,getConfig().getDouble("server-shop.items."+m),()->p.getInventory().addItem(new ItemStack(Material.valueOf(m))));}}}
@EventHandler public void close(InventoryCloseEvent e){if(e.getView().getTitle().equals(col("&c&lKOSZ"))){e.getInventory().clear();e.getPlayer().sendMessage(col("&aKosz wyczyszczony."));}}
void buy(Player p,double price,Runnable r){if(bal(p.getName())<price){p.sendMessage(msg("no-money"));return;}add(p.getName(),-price);r.run();p.sendMessage(pref()+col("&aKupiono za &e"+money(price)+"$"));}
double sellAll(Player p){double total=0;ConfigurationSection s=getConfig().getConfigurationSection("sell");if(s==null)return 0;for(String n:s.getKeys(false)){try{Material m=Material.valueOf(n);double pr=s.getDouble(n);for(ItemStack it:p.getInventory().getContents())if(it!=null&&it.getType()==m){total+=it.getAmount()*pr;it.setAmount(0);}}catch(Exception ignored){}}add(p.getName(),total);return total;}
ItemStack btn(Material m,String name,String a,List<String> lore){ItemStack it=new ItemStack(m);ItemMeta meta=it.getItemMeta();meta.setDisplayName(col(name));ArrayList<String> l=new ArrayList<>();for(String x:lore)l.add(col(x));meta.setLore(l);meta.getPersistentDataContainer().set(action,PersistentDataType.STRING,a);it.setItemMeta(meta);return it;}void fill(Inventory inv){ItemStack g=btn(Material.BLACK_STAINED_GLASS_PANE," ","none",List.of());for(int i=0;i<inv.getSize();i++)inv.setItem(i,g);}String act(ItemStack it){return it!=null&&it.hasItemMeta()?it.getItemMeta().getPersistentDataContainer().get(action,PersistentDataType.STRING):null;}double bal(String p){return data.getDouble("players."+p.toLowerCase(),0);}void add(String p,double a){data.set("players."+p.toLowerCase(),Math.max(0,bal(p)+a));save();}double parse(String s){try{return Double.parseDouble(s);}catch(Exception e){return 0;}}String money(double v){return v==(long)v?String.valueOf((long)v):String.format(Locale.US,"%.2f",v);}void save(){try{data.save(f);}catch(Exception e){e.printStackTrace();}}String pref(){return col(getConfig().getString("messages.prefix","&6&lRynek &8» &r"));}String msg(String k){return pref()+col(getConfig().getString("messages."+k,""));}String col(String s){return ChatColor.translateAlternateColorCodes('&',s==null?"":s);} }
